mapper.select:
SELECT ID, EDU_VIDEO_TITLE, EDU_VIDEO_DETAIL, EDU_VIDEO_TYPE, EDU_VIDEO_URL, EDU_VIDEO_THUMBNAIL_URL, EDU_VIDEO_CREATE_AT
FROM TBL_EDU_VIDEO
WHERE ID = #{id}

mapper.update:
UPDATE TBL_EDU_VIDEO
SET EDU_VIDEO_TITLE = #{eduVideoTitle}, EDU_VIDEO_DETAIL = #{eduVideoDetail},
    EDU_VIDEO_TYPE = #{eduVideoType}, EDU_VIDEO_URL = #{eduVideoUrl}, EDU_VIDEO_THUMBNAIL_URL = #{eduVideoThumbnailUrl}
WHERE ID = #{id}
